"""
Pose Module - Optimized
By: Computer Vision Zone
Website: https://www.computervision.zone/

Optimizations applied:
  1. Resize frame before inference (biggest speedup)
  2. Real millisecond timestamps for VIDEO mode stability
  3. Numpy-vectorized landmark extraction
  4. Threaded inference so display never blocks
  5. Frame skipping support
"""

import cv2
import math
import os
import time
import threading
import urllib.request

import numpy as np
import mediapipe as mp
from mediapipe.tasks import python
from mediapipe.tasks.python import vision


class PoseDetector:
    """
    Pose Detection using latest MediaPipe Tasks API
    CVZone-compatible output — optimized for real-time performance
    """

    MODEL_URL = "https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_lite/float16/1/pose_landmarker_lite.task"
    MODEL_NAME = "pose_landmarker.task"

    def __init__(self,
                 staticMode=False,
                 modelComplexity=1,
                 smoothLandmarks=True,
                 enableSegmentation=False,
                 smoothSegmentation=True,
                 detectionCon=0.5,
                 trackCon=0.5,
                 inferWidth=480,       # resize width before inference; set None to disable
                 skipFrames=1,         # run inference every N frames (1 = every frame)
                 useThread=True):      # run inference in background thread

        self.staticMode = staticMode
        self.modelComplexity = modelComplexity
        self.detectionCon = detectionCon
        self.trackCon = trackCon
        self.inferWidth = inferWidth
        self.skipFrames = max(1, skipFrames)
        self.useThread = useThread

        self._downloadModel()

        base_options = python.BaseOptions(model_asset_path=self.MODEL_NAME)
        options = vision.PoseLandmarkerOptions(
            base_options=base_options,
            running_mode=vision.RunningMode.VIDEO,
            num_poses=1,
            min_pose_detection_confidence=detectionCon,
            min_tracking_confidence=trackCon,
            output_segmentation_masks=False
        )
        self.detector = vision.PoseLandmarker.create_from_options(options)

        # Timing & frame state
        self._start_time = time.time()
        self._frame_count = 0
        self.results = None

        # Threading support
        self._lock = threading.Lock()
        self._latest_frame = None      # BGR frame queued for inference
        self._pending = False          # inference in-flight flag

        self.lmList = []
        self.bboxInfo = {}

    # ------------------------------------------------------------------
    # Model download
    # ------------------------------------------------------------------
    def _downloadModel(self):
        if not os.path.exists(self.MODEL_NAME):
            print("Downloading MediaPipe Pose model...")
            urllib.request.urlretrieve(self.MODEL_URL, self.MODEL_NAME)
            print("Download complete.")

    # ------------------------------------------------------------------
    # Internal inference (can run on a worker thread)
    # ------------------------------------------------------------------
    def _run_inference(self, img_rgb, timestamp_ms):
        mp_image = mp.Image(image_format=mp.ImageFormat.SRGB, data=img_rgb)
        result = self.detector.detect_for_video(mp_image, timestamp_ms)
        with self._lock:
            self.results = result
            self._pending = False

    # ------------------------------------------------------------------
    # Pose detection
    # ------------------------------------------------------------------
    def findPose(self, img, draw=True):
        self._frame_count += 1
        self.imgH, self.imgW = img.shape[:2]

        # --- Frame skip: only queue new inference every N frames ---
        if self._frame_count % self.skipFrames == 0:
            # Resize for faster inference while keeping original for display
            if self.inferWidth and self.inferWidth < self.imgW:
                scale = self.inferWidth / self.imgW
                infer_img = cv2.resize(img, (self.inferWidth, int(self.imgH * scale)),
                                       interpolation=cv2.INTER_LINEAR)
            else:
                infer_img = img

            img_rgb = cv2.cvtColor(infer_img, cv2.COLOR_BGR2RGB)
            timestamp_ms = int((time.time() - self._start_time) * 1000)

            if self.useThread:
                # Only spawn a new thread if the previous one finished
                with self._lock:
                    already_pending = self._pending
                    if not already_pending:
                        self._pending = True

                if not already_pending:
                    t = threading.Thread(
                        target=self._run_inference,
                        args=(img_rgb, timestamp_ms),
                        daemon=True
                    )
                    t.start()
            else:
                self._run_inference(img_rgb, timestamp_ms)

        # --- Draw last known landmarks on the ORIGINAL full-res frame ---
        with self._lock:
            results_snapshot = self.results

        if results_snapshot and results_snapshot.pose_landmarks and draw:
            for lm in results_snapshot.pose_landmarks[0]:
                x = int(lm.x * self.imgW)
                y = int(lm.y * self.imgH)
                cv2.circle(img, (x, y), 3, (0, 255, 0), -1)

        return img

    # ------------------------------------------------------------------
    # Landmark extraction  (numpy-vectorised)
    # ------------------------------------------------------------------
    def findPosition(self, img, draw=True, bboxWithHands=False):
        self.lmList = []
        self.bboxInfo = {}

        with self._lock:
            results_snapshot = self.results

        if not results_snapshot or not results_snapshot.pose_landmarks:
            return self.lmList, self.bboxInfo

        h, w = img.shape[:2]
        lms = results_snapshot.pose_landmarks[0]

        # Vectorised coordinate conversion — one numpy op instead of a loop
        raw = np.array([[lm.x, lm.y, lm.z] for lm in lms], dtype=np.float32)
        raw[:, 0] *= w
        raw[:, 1] *= h
        raw[:, 2] *= w
        coords = raw.astype(np.int32)
        self.lmList = coords.tolist()

        # Bounding box (same CVZone logic)
        ad = abs(self.lmList[12][0] - self.lmList[11][0]) // 2

        if bboxWithHands:
            x1 = self.lmList[16][0] - ad
            x2 = self.lmList[15][0] + ad
        else:
            x1 = self.lmList[12][0] - ad
            x2 = self.lmList[11][0] + ad

        y1 = self.lmList[1][1] - ad
        y2 = self.lmList[29][1] + ad

        bbox = (x1, y1, x2 - x1, y2 - y1)
        cx = x1 + bbox[2] // 2
        cy = y1 + bbox[3] // 2

        self.bboxInfo = {"bbox": bbox, "center": (cx, cy)}

        if draw:
            cv2.rectangle(img, bbox, (255, 0, 255), 2)
            cv2.circle(img, (cx, cy), 5, (255, 0, 0), -1)

        return self.lmList, self.bboxInfo

    # ------------------------------------------------------------------
    # Distance
    # ------------------------------------------------------------------
    def findDistance(self, p1, p2, img=None, color=(255, 0, 255), scale=5):
        x1, y1 = p1
        x2, y2 = p2
        cx, cy = (x1 + x2) // 2, (y1 + y2) // 2
        length = math.hypot(x2 - x1, y2 - y1)
        info = (x1, y1, x2, y2, cx, cy)

        if img is not None:
            cv2.line(img, (x1, y1), (x2, y2), color, 2)
            cv2.circle(img, (x1, y1), scale, color, -1)
            cv2.circle(img, (x2, y2), scale, color, -1)
            cv2.circle(img, (cx, cy), scale, color, -1)

        return length, img, info

    # ------------------------------------------------------------------
    # Angle
    # ------------------------------------------------------------------
    def findAngle(self, p1, p2, p3, img=None, color=(255, 0, 255), scale=5):
        x1, y1 = p1
        x2, y2 = p2
        x3, y3 = p3

        angle = math.degrees(
            math.atan2(y3 - y2, x3 - x2) -
            math.atan2(y1 - y2, x1 - x2)
        )
        if angle < 0:
            angle += 360

        if img is not None:
            cv2.line(img, (x1, y1), (x2, y2), color, 2)
            cv2.line(img, (x3, y3), (x2, y2), color, 2)
            cv2.circle(img, (x1, y1), scale, color, -1)
            cv2.circle(img, (x2, y2), scale, color, -1)
            cv2.circle(img, (x3, y3), scale, color, -1)
            cv2.putText(img, str(int(angle)),
                        (x2 - 50, y2 + 50),
                        cv2.FONT_HERSHEY_PLAIN, 2, color, 2)

        return angle, img

    # ------------------------------------------------------------------
    # Angle check
    # ------------------------------------------------------------------
    def angleCheck(self, myAngle, targetAngle, offset=20):
        return targetAngle - offset < myAngle < targetAngle + offset


# ----------------------------------------------------------------------
# FPS helper (optional, handy for debugging speed)
# ----------------------------------------------------------------------
class FPS:
    def __init__(self):
        self._start = time.time()
        self._count = 0
        self.fps = 0

    def update(self):
        self._count += 1
        elapsed = time.time() - self._start
        if elapsed >= 1.0:
            self.fps = self._count / elapsed
            self._count = 0
            self._start = time.time()
        return self.fps

    def draw(self, img, pos=(10, 40), color=(0, 255, 0)):
        cv2.putText(img, f"FPS: {int(self.fps)}", pos,
                    cv2.FONT_HERSHEY_PLAIN, 2, color, 2)


# ----------------------------------------------------------------------
# Main demo
# ----------------------------------------------------------------------
def main():
    cap = cv2.VideoCapture(2)
    # Optional: cap.set(cv2.CAP_PROP_FRAME_WIDTH, 640)
    # Optional: cap.set(cv2.CAP_PROP_FRAME_HEIGHT, 480)

    detector = PoseDetector(
        staticMode=False,
        modelComplexity=1,
        smoothLandmarks=True,
        enableSegmentation=False,
        smoothSegmentation=True,
        detectionCon=0.5,
        trackCon=0.5,
        inferWidth=480,   # inference at 480 px wide, display at full res
        skipFrames=1,     # increase to 2 for extra speed (adds slight lag)
        useThread=True    # background inference = smooth display loop
    )

    fps_counter = FPS()

    while True:
        success, img = cap.read()
        if not success:
            break

        img = detector.findPose(img)
        lmList, bboxInfo = detector.findPosition(img, draw=True, bboxWithHands=False)

        if lmList:
            center = bboxInfo["center"]
            cv2.circle(img, center, 5, (255, 0, 255), cv2.FILLED)

            length, img, info = detector.findDistance(
                lmList[11][0:2], lmList[15][0:2],
                img=img, color=(255, 0, 0), scale=10
            )

            angle, img = detector.findAngle(
                lmList[11][0:2], lmList[13][0:2], lmList[15][0:2],
                img=img, color=(0, 0, 255), scale=10
            )

            isCloseAngle50 = detector.angleCheck(myAngle=angle, targetAngle=50, offset=10)
            print(isCloseAngle50)

        fps_counter.update()
        fps_counter.draw(img)

        cv2.imshow("Pose - Optimized", img)
        if cv2.waitKey(1) & 0xFF == ord('q'):
            break

    cap.release()
    cv2.destroyAllWindows()


if __name__ == "__main__":
    main()